// Corrected function to calculate the total height of the CSS grid
function solve(s) {
    let totalHeight = 0;
    let rows = s.split(',').map(row => row.trim());
    let currentHeight = 0;
    for (let i = 0; i < rows.length; i++) {
        if (rows[i].includes('gap')) {
            let [height, gapSize] = rows[i].split(' gap');
            currentHeight += parseInt(height);
            if (i < rows.length - 1) {
                currentHeight += parseInt(gapSize);
            }
        } else {
            totalHeight += parseInt(rows[i]);
        }
    }
    return totalHeight.toString();
}

