class Solution:
    def solve(self, s: str) -> str:
        total_height = 0
        rows = s.split(',').map(row => row.strip())
        current_height = 0
        for i in range(len(rows)):
            if 'gap' in rows[i]:
                height, gap_size = rows[i].split(' gap')
                current_height += int(height)
                if i < len(rows) - 1:
                    current_height += int(gap_size)
            else:
                total_height += int(rows[i])
        return str(total_height)
